svg.script:
(function () {
  var svg = document.documentElement;
  svg._chartInit = function (svgEl, ctx) {
var svg         = document.getElementById('root');
  var dataLayerEl = document.querySelector('.data-layer');

  /* §2 — isDark hoisted before all build and animation code */

  var dataItemEls = Array.prototype.slice.call(document.querySelectorAll('.data-item'));
  dataItemEls.forEach(function(itemEl) {
    itemEl.addEventListener('mouseenter', function() {
      if (dataLayerEl) dataLayerEl.classList.add('hovering');
      dataItemEls.forEach(function(x) { x.classList.remove('active'); }); /* §4 clear stale */
      itemEl.classList.add('active');
    });
    itemEl.addEventListener('mouseleave', function() {
      itemEl.classList.remove('active');
      if (dataLayerEl) dataLayerEl.classList.remove('hovering');
    });
  });
  var bbDelays = [0, 0.25, 0.50, 0.75, 1.00, 1.25, 1.50, 1.75];
  document.querySelectorAll('.data-body').forEach(function(bb, i) {
    bb.style.animation = 'dataFadeIn 0.8s ease-out ' + bbDelays[i] + 's';
    bb.addEventListener('animationend', function() {
      bb.style.animation = 'none';
      bb.classList.add('visible');
    }, { once: true });
  });
  /* gate hover on .ready after last box animation: 1.75s + 0.8s + 100ms buffer */
  setTimeout(function() { if (dataLayerEl) dataLayerEl.classList.add('ready'); }, (1.75 + 0.8) * 1000 + 100);
  };
  if (window.bootstrapChart) { window.bootstrapChart(svg); }
}());
